import{C as n,o as t,c as o,a5 as a,E as l}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"1. Gossip protocol — cluster membership","description":"","frontmatter":{},"headers":[],"relativePath":"module-5/1-gossip.md","filePath":"module-5/1-gossip.md","lastUpdated":1780937944000}'),p={name:"module-5/1-gossip.md"},g=Object.assign(p,{setup(r){const i={id:"m5-1-gossip",title:"🧠 Mini-check: Gossip",intro:"3 питання — gossip basics.",questions:[{type:"mcq",q:"Що з цього передається через gossip? (обери всі)",options:["Cluster nodes list","Validator versions","Vote signatures","TXs from clients"],correct:[0,1,2],explanation:"Gossip = membership + metadata. TX submission separate (TPU). Votes можуть передаватись через gossip або як regular TX. Module 5.1."},{type:"command",q:"Як подивитись всі nodes у cluster через gossip?",accepts:["solana gossip","sudo /home/solana/ag/bin/solana gossip --url http://localhost:8899"],ideal:"solana gossip",explanation:"solana gossip lists всі visible nodes з gossip data: identity, IP, ports, version. Module 5.1."},{type:"explain",q:"Поясни як gossip protocol дозволяє nodes discover один одного без centralized registry.",ideal:`Gossip — epidemic propagation. Workflow:
1. New node connects до entrypoint (well-known seed node, e.g., 64.130.37.11:8000 для Alpenglow)
2. Entrypoint shares свій table відомих nodes
3. New node pings цих nodes, building local table
4. Periodically всі nodes exchange tables з random peers
5. Через кілька rounds (~5-10 sec) all nodes converge до consistent view of cluster

Ключове: decentralized — no single source of truth. Entrypoints lower trust requirement (just bootstrap). Gossip self-healing — якщо node disappears, gossip propagates absence.

Gossiped info: identity pubkey, IP+ports, validator version, last activity timestamp, optional metadata (validator-info publishing).

Це чому твій validator може join Alpenglow cluster knowing тільки 2 entrypoint IPs — gossip handles the rest.`,explanation:"Module 5.1."}]};return(h,s)=>{const e=n("Quiz");return t(),o("div",null,[s[0]||(s[0]=a(`<h1 id="_1-gossip-protocol-—-cluster-membership" tabindex="-1">1. Gossip protocol — cluster membership <a class="header-anchor" href="#_1-gossip-protocol-—-cluster-membership" aria-label="Permalink to &quot;1. Gossip protocol — cluster membership&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Gossip</strong> — epidemic protocol через який cluster nodes discover один одного, share metadata, propagate cluster state. Не використовується для TX submission (це TPU) або block propagation (це turbine). Gossip = &quot;who&#39;s in cluster + what they know&quot;.</p><h2 id="концепти" tabindex="-1">Концепти <a class="header-anchor" href="#концепти" aria-label="Permalink to &quot;Концепти&quot;">​</a></h2><h3 id="чому-gossip" tabindex="-1">Чому gossip <a class="header-anchor" href="#чому-gossip" aria-label="Permalink to &quot;Чому gossip&quot;">​</a></h3><p>Distributed system needs membership: who&#39;s у cluster, які їх addresses, які versions. Без centralized registry — gossip.</p><p>Кожен node periodically:</p><ol><li>Picks random peers</li><li>Shares own state (membership table)</li><li>Receives peer&#39;s table</li><li>Merges → updated view</li></ol><p>Через few rounds (~5-10 sec) cluster converges до consistent view.</p><h3 id="що-gossip-carries" tabindex="-1">Що gossip carries <a class="header-anchor" href="#що-gossip-carries" aria-label="Permalink to &quot;Що gossip carries&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ContactInfo {</span></span>
<span class="line"><span>    pubkey: validator identity</span></span>
<span class="line"><span>    gossip: IP:port    // gossip port</span></span>
<span class="line"><span>    tpu: IP:port       // TPU (для receiving TXs)</span></span>
<span class="line"><span>    tvu: IP:port       // TVU (для receiving shreds)</span></span>
<span class="line"><span>    repair: IP:port    // repair service</span></span>
<span class="line"><span>    rpc: IP:port       // optional RPC</span></span>
<span class="line"><span>    version: agave/solana version</span></span>
<span class="line"><span>    timestamps: when seen last</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Vote        // vote signatures (sometimes)</span></span>
<span class="line"><span>EpochSlots  // slots validator has seen</span></span>
<span class="line"><span>SnapshotHashes // for snapshot fetching</span></span>
<span class="line"><span>ValidatorInfo // optional human-readable info (name, logo, website)</span></span></code></pre></div><h3 id="entrypoints-—-bootstrap" tabindex="-1">Entrypoints — bootstrap <a class="header-anchor" href="#entrypoints-—-bootstrap" aria-label="Permalink to &quot;Entrypoints — bootstrap&quot;">​</a></h3><p>Bootstrap problem: new node knows nothing. Solution: <strong>entrypoint</strong> — well-known seed nodes у constants/genesis.</p><p>З Constants твого Alpenglow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrypoint #1: 64.130.37.11:8000</span></span>
<span class="line"><span>Entrypoint #2: 213.239.141.16:8001</span></span></code></pre></div><p>New validator connects до entrypoint → gets initial peers list → начинає gossip → joins cluster.</p><p>Якщо entrypoints down — нові nodes can&#39;t join (existing nodes продовжують працювати).</p><h3 id="solana-gossip-command" tabindex="-1">solana gossip command <a class="header-anchor" href="#solana-gossip-command" aria-label="Permalink to &quot;solana gossip command&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gossip</span></span></code></pre></div><p>Output (similar до):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IP Address       | Identity                                       | Gossip | TPU      | RPC          | Version    | Feature Set</span></span>
<span class="line"><span>64.130.37.11     | 9ZmGqB...                                      | 8001   | 8003     | 8899         | 0.4.0      | -</span></span>
<span class="line"><span>213.239.141.16   | 8KsGcM...                                      | 8001   | 8003     | none         | 0.4.0      | -</span></span>
<span class="line"><span>WNX0016778       | DSDefivSL...                                   | 8001   | 8003     | 8899         | 0.4.0      | -</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>Всі знайдені через gossip nodes. Якщо твій validator не з&#39;являється — gossip issue.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="cluster-restart-і-gossip" tabindex="-1">Cluster restart і gossip <a class="header-anchor" href="#cluster-restart-і-gossip" aria-label="Permalink to &quot;Cluster restart і gossip&quot;">​</a></h3><p>Після cluster restart (новий genesis) — gossip restarts. New genesis hash = different shred_version. Validators з old shred_version filtered out (incompatible).</p><p>Якщо ти бачиш &quot;no peers&quot; після restart — gossip ще не converged або shred_version mismatch.</p><h3 id="validator-info-publishing" tabindex="-1">Validator-info publishing <a class="header-anchor" href="#validator-info-publishing" aria-label="Permalink to &quot;Validator-info publishing&quot;">​</a></h3><p><code>solana validator-info publish</code> updates gossip з human-readable info (validator name, logo, website). З §17 cheatsheet.</p><h2 id="hands-on-exercise" tabindex="-1">Hands-on exercise <a class="header-anchor" href="#hands-on-exercise" aria-label="Permalink to &quot;Hands-on exercise&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gossip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8899</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Скільки nodes у cluster</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gossip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8899</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Search для свого validator</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gossip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8899</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DSDefivSL</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Mainnet (з ноутбука)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gossip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mainnet-beta</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,31)),l(e,{data:i}),s[1]||(s[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#g"><code>Gossip</code></a>, <a href="/glossary#e"><code>Entrypoint</code></a>, <a href="/glossary#c"><code>ContactInfo</code></a>, <a href="/glossary#c"><code>Cluster membership</code></a>, <a href="/glossary#s"><code>Shred version</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/validator/gossip" target="_blank" rel="noreferrer">Anza: Gossip Service</a></li><li><a href="https://docs.anza.xyz/cluster/overview" target="_blank" rel="noreferrer">Anza: Cluster Overview</a></li></ul><hr><p><strong>Наступне:</strong> <a href="/module-5/2-turbine">2. Turbine →</a></p>',6))])}}});export{c as __pageData,g as default};
